prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?parent WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?parent .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("genehmigten")))
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("zurück")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orgName ?created WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?parent .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("genehmigten und unterzeichneten Antrag zurücksenden")))

  ?parent tai:belongsTo* ?model .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org .
  ?org bbo:name ?orgName .
  OPTIONAL { ?model tai:modelCreated ?created . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?parent ?parentType ?parentName ?grandParent ?grandType ?grandName WHERE {
  VALUES ?taskName { "genehmigten und unterzeichneten Antrag zurücksenden" }
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?parent .
  OPTIONAL { ?parent a ?parentType . }
  OPTIONAL { ?parent bbo:name ?parentName . }
  OPTIONAL {
    ?parent tai:belongsTo ?grandParent .
    OPTIONAL { ?grandParent a ?grandType . }
    OPTIONAL { ?grandParent bbo:name ?grandName . }
  }
}
LIMIT 25

